failure.message:
assert '<h1>' in '<style>
.drhp-document {
    font-family: 'Times New Roman', Times, serif;
    font-size: 12pt;
    line-height: 1.5;
    color: #000;
}

/* Title and Headings */
.drhp-title {
    font-size: 18pt;
    font-weight: bold;
    text-align: center;
    margin: 24px 0 16px 0;
    text-transform: uppercase;
}
.drhp-h1, .drhp-section {
    font-size: 16pt;
    font-weight: bold;
    margin: 20px 0 12px 0;
    page-break-after: avoid;
}
.drhp-h2, .drhp-subsection {
    font-size: 14pt;
    font-weight: bold;
    margin: 16px 0 10px 0;
    page-break-after: avoid;
}
.drhp-h3 { font-size: 13pt; font-weight: bold; margin: 14px 0 8px 0; }
.drhp-h4 { font-size: 12pt; font-weight: bold; margin: 12px 0 6px 0; }
.drhp-h5 { font-size: 11pt; font-weight: bold; margin: 10px 0 4px 0; }
.drhp-h6 { font-size: 10pt; font-weight: bold; margin: 8px 0 4px 0; }

/* SEBI Specific Clause Styles */
.drhp-clause {
    margin: 8px 0;
    text-align: justify;
}
.drhp-sub-clause {
    margin: 6px 0 6px 36px;
    text-align: justify;
}
.drhp-para {
    margin: 8px 0;
    text-align: justify;
}

/* Legal and Risk Styles */
.drhp-legal {
    font-style: italic;
  ...ter { margin-left: auto; margin-right: auto; }
.drhp-image-caption {
    font-size: 10pt;
    text-align: center;
    color: #666;
    margin-top: 4px;
}

/* Hyperlink Styles */
.drhp-link {
    color: #1DA1F2;
    text-decoration: underline;
}
.drhp-bookmark {
    color: inherit;
    text-decoration: none;
}

/* Page Break */
.drhp-page-break {
    page-break-before: always;
    border-top: 2px dashed #ccc;
    margin: 30px 0;
    height: 0;
}

/* Spacing Preservation */
.drhp-space-before { margin-top: var(--space-before, 0); }
.drhp-space-after { margin-bottom: var(--space-after, 0); }
</style>
<div class="drhp-document">
<h1 class="drhp-h1" style="text-align: center; margin-top: 31.991999999999997px">Test DRHP Document</h1>
<p class="drhp-normal"><strong>Bold text</strong> and <em>italic text</em></p>
<h2 class="drhp-h2" style="margin-top: 13.33px">Section 1</h2>
<p class="drhp-normal">Test paragraph content.</p>
<table class="drhp-table">
<tr>
<th>Header 1</th>
<th>Header 2</th>
</tr>
<tr>
<td>Data 1</td>
<td>Data 2</td>
</tr>
</table>
<p class="drhp-list-bullet">List item 1</p>
<p class="drhp-list-bullet">List item 2</p>
</div>'

